public class Animal {
    String name;
    public Animal(String name) {
        this.name = name;
    }
    public void speak() {
        System.out.println(name + " makes noise");
    }
    public String toString() {
        return "Animal: " + name;
    }
}

public class Dog extends Animal {
    String breed;

    public Dog(String name, String breed) {
        super(name);        // call parent constructor!
        this.breed = breed;
    }

    @Override
    public void speak() {   // override parent method
        System.out.println(name + " barks!");
    }

    public void fetch() {   // new method
        System.out.println(name + " fetches!");
    }
}

Dog d = new Dog("Rex", "Lab");
d.speak();   // Rex barks!  (overridden)
d.fetch();   // Rex fetches!

class Vehicle {
    int speed;
    Vehicle(int speed) { this.speed = speed; }
    String info() { return "Speed: " + speed; }
}

class Car extends Vehicle {
    String brand;
    Car(String brand, int speed) {
        super(speed);       // parent constructor
        this.brand = brand;
    }

    @Override
    String info() {
        return brand + " — " + super.info();
        // calls Vehicle.info() then extends it
    }
}

Car c = new Car("BMW", 200);
System.out.println(c.info()); // BMW — Speed: 200

