    new Cat("Whiskers"),
    new Bird("Tweety")
};

// Same code — different behavior per type!
for (Animal a : zoo) {
    a.speak();   // Rex barks! / Whiskers meows! / Tweety chirps!
}

// instanceof check:
if (zoo[0] instanceof Dog) {
    Dog d = (Dog) zoo[0];  // safe downcast
    d.fetch();             // Dog-specific method
}

abstract class Shape {
    abstract double area();  // no body — subclass MUST implement

    void display() {  // concrete method — shared
        System.out.println("Area: " + area());
    }
}

class Circle extends Shape {
    double r;
    Circle(double r){this.r=r;}

    @Override
    double area(){return Math.PI*r*r;}
}

Shape s = new Circle(5);
s.display(); // Area: 78.5...

interface Flyable {
    void fly();           // implicitly public abstract
    default void land(){  // Java 8 default method
        System.out.println("Landing...");
    }
}

interface Swimmable {
    void swim();
}

// Duck implements BOTH interfaces:
class Duck extends Animal
             implements Flyable, Swimmable {
    public void fly(){System.out.println("Duck flies");}
    public void swim(){System.out.println("Duck swims");}
}

Flyable f = new Duck();  // polymorphism with interface type!
f.fly();
f.land();

