// Generic class:
class Box<T> {
    private T value;
    Box(T v){ this.value = v; }
    T get(){ return value; }
}

Box<Integer> iBox = new Box<>(42);
Box<String> sBox = new Box<>("Hello");
System.out.println(iBox.get()); // 42
System.out.println(sBox.get()); // Hello
// Type safe — no casting needed!

try {
    int[] arr = new int[3];
    arr[5] = 10;  // ArrayIndexOutOfBoundsException
} catch (ArrayIndexOutOfBoundsException e) {
    System.out.println("OOB: " + e.getMessage());
} catch (Exception e) {
    System.out.println("Generic: " + e.getMessage());
} finally {
    System.out.println("Always runs!");
}

